1	//! cor24-dbg: GDB-like CLI debugger for the MakerLisp COR24 processor
2	//!
3	//! Usage:
4	//!   cor24-dbg <file.lgo>           Load an LGO file and start debugging
5	//!   cor24-dbg --entry 0x93 <file>  Set entry point address
6	
7	use cor24_emulator::emulator::{EmulatorCore, StopReason};
8	use std::io::{self, BufRead, Write};
9	
10	const COPYRIGHT: &str = "Copyright (c) 2026 Michael A Wright";
11	const LICENSE: &str = "MIT";
12	const REPOSITORY: &str = "https://github.com/sw-embed/sw-cor24-emulator";
13	
14	fn print_version() {
15	    println!(
16	        "cor24-dbg {}\n{}\nLicense: {}\nRepository: {}\n\nBuild Information:\n  Host: {}\n  Commit: {}\n  Timestamp: {}",
17	        env!("CARGO_PKG_VERSION"),
18	        COPYRIGHT,
19	        LICENSE,
20	        REPOSITORY,
21	        env!("VERGEN_BUILD_HOST"),
22	        env!("VERGEN_GIT_SHA_SHORT"),
23	        env!("VERGEN_BUILD_TIMESTAMP"),
24	    );
25	}
26	
27	fn main() {
28	    let args: Vec<String> = std::env::args().collect();
29	
30	    if args.contains(&"-V".to_string()) || args.contains(&"--version".to_string()) {
31	        print_version();
32	        return;
33	    }
34	
35	    if args.len() < 2 || args.contains(&"-h".to_string()) || args.contains(&"--help".to_string()) {
36	        eprintln!("cor24-dbg: MakerLisp COR24 debugger\n");
37	        eprintln!("Usage:");
38	        eprintln!("  cor24-dbg <file.lgo>                Load LGO file");
39	        eprintln!("  cor24-dbg --entry <addr> <file.lgo>  Set entry point");
40	        eprintln!("  cor24-dbg -V | --version             Show version info");
41	        eprintln!("\nCommands: run, step, break, info, examine, disas, reset, quit");
42	        if args.len() < 2 {
43	            std::process::exit(1);
44	        }
45	        return;
46	    }
47	
48	    let mut entry_override: Option<u32> = None;
49	    let mut filename = None;
50	
51	    let mut i = 1;
52	    while i < args.len() {
53	        match args[i].as_str() {
54	            "--entry" | "-e" => {
55	                i += 1;
56	                if i < args.len() {
57	                    entry_override = Some(parse_addr(&args[i]).unwrap_or_else(|| {
58	                        eprintln!("Bad address: {}", args[i]);
59	                        std::process::exit(1);
60	                    }));
61	                }
62	            }
63	            _ => {
64	                filename = Some(args[i].clone());
65	            }
66	        }
67	        i += 1;
68	    }
69	
70	    let filename = filename.unwrap_or_else(|| {
71	        eprintln!("No file specified");
72	        std::process::exit(1);
73	    });
74	
75	    let mut dbg = Debugger::new();
76	
77	    if let Err(e) = dbg.load_file(&filename, entry_override) {
78	        eprintln!("Error loading {}: {}", filename, e);
79	        std::process::exit(1);
80	    }
81	
82	    dbg.repl();
83	}
84	
85	struct Debugger {
86	    emu: EmulatorCore,
87	    loaded: bool,
88	    /// Track UART output position for incremental printing
89	    uart_printed: usize,
90	}
91	
92	impl Debugger {
93	    fn new() -> Self {
94	        Self {
95	            emu: EmulatorCore::new(),
96	            loaded: false,
97	            uart_printed: 0,
98	        }
99	    }
100	
101	    fn load_file(&mut self, path: &str, entry: Option<u32>) -> Result<(), String> {
102	        let content =
103	            std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {}", e))?;
104	
105	        let bytes = self.emu.load_lgo(&content, entry)?;
106	        self.loaded = true;
107	        self.uart_printed = 0;
108	
109	        println!("Loaded {} bytes from {}", bytes, path);
110	        println!("PC = 0x{:06X}", self.emu.pc());
111	        Ok(())
112	    }
113	
114	    fn repl(&mut self) {
115	        let stdin = io::stdin();
116	        let mut last_cmd = String::new();
117	
118	        loop {
119	            print!("(cor24) ");
120	            io::stdout().flush().ok();
121	
122	            let mut line = String::new();
123	            if stdin.lock().read_line(&mut line).unwrap_or(0) == 0 {
124	                println!();
125	                break;
126	            }
127	            let line = line.trim().to_string();
128	
129	            let cmd = if line.is_empty() {
130	                last_cmd.clone()
131	            } else {
132	                last_cmd = line.clone();
133	                line
134	            };
135	
136	            if cmd.is_empty() {
137	                continue;
138	            }
139	
140	            let parts: Vec<&str> = cmd.splitn(2, ' ').collect();
141	            let arg = if parts.len() > 1 { parts[1].trim() } else { "" };
142	
143	            match parts[0] {
144	                "q" | "quit" | "exit" => break,
145	                "r" | "run" => self.cmd_run(arg),
146	                "s" | "step" | "si" => self.cmd_step(arg),
147	                "n" | "next" => self.cmd_next(),
148	                "c" | "cont" | "continue" => self.cmd_continue(),
149	                "b" | "break" => self.cmd_break(arg),
150	                "d" | "delete" => self.cmd_delete(arg),
151	                "i" | "info" => self.cmd_info(arg),
152	                "x" | "examine" => self.cmd_examine(arg),
153	                "p" | "print" => self.cmd_print(arg),
154	                "disas" | "disassemble" => self.cmd_disas(arg),
155	                "load" => {
156	                    if arg.is_empty() {
157	                        println!("Usage: load <file.lgo>");
158	                    } else if let Err(e) = self.load_file(arg, None) {
159	                        println!("Error: {}", e);
160	                    }
161	                }
162	                "reset" => {
163	                    self.emu.reset();
164	                    self.uart_printed = 0;
165	                    println!("CPU reset. PC = 0x{:06X}", self.emu.pc());
166	                }
167	                "t" | "trace" => self.cmd_trace(arg),
168	                "uart" => self.cmd_uart(arg),
169	                "led" => self.cmd_led(),
170	                "button" | "btn" => self.cmd_button(arg),
171	                "help" | "h" | "?" => self.cmd_help(),
172	                _ => println!("Unknown command: '{}'. Type 'help' for commands.", parts[0]),
173	            }
174	        }
175	    }
176	
177	    fn print_new_uart(&mut self) {
178	        let output = self.emu.get_uart_output();
179	        if output.len() > self.uart_printed {
180	            print!("{}", &output[self.uart_printed..]);
181	            io::stdout().flush().ok();
182	            self.uart_printed = output.len();
183	        }
184	    }
185	
186	    fn cmd_run(&mut self, arg: &str) {
187	        if self.emu.is_halted() {
188	            println!("CPU is halted. Use 'reset' to restart.");
189	            return;
190	        }
191	
192	        let max: u64 = if arg.is_empty() {
193	            100_000_000
194	        } else {
195	            arg.replace('_', "").parse().unwrap_or(100_000_000)
196	        };
197	
198	        self.emu.resume();
199	        let result = self.emu.run_batch(max);
200	        self.print_new_uart();
201	
202	        match result.reason {
203	            StopReason::Halted => {
204	                println!(
205	                    "\nCPU halted after {} instructions",
206	                    result.instructions_run
207	                );
208	                self.cmd_trace("10");
209	            }
210	            StopReason::Breakpoint(addr) => {
211	                println!("Breakpoint at 0x{:06X}", addr);
212	            }
213	            StopReason::InvalidInstruction(byte) => {
214	                println!(
215	                    "\nInvalid instruction 0x{:02X} after {} instructions",
216	                    byte, result.instructions_run
217	                );
218	            }
219	            StopReason::CycleLimit => {
220	                println!(
221	                    "\nStopped after {} instructions (limit). PC = 0x{:06X}",
222	                    result.instructions_run,
223	                    self.emu.pc()
224	                );
225	            }
226	            StopReason::Paused => {}
227	        }
228	
229	        self.show_location();
230	    }
231	
232	    fn cmd_step(&mut self, arg: &str) {
233	        let n: u64 = if arg.is_empty() {
234	            1
235	        } else {
236	            arg.parse().unwrap_or(1)
237	        };
238	
239	        for _ in 0..n {
240	            if self.emu.is_halted() {
241	                println!("CPU is halted.");
242	                return;
243	            }
244	            self.emu.step();
245	        }
246	
247	        self.print_new_uart();
248	        self.show_location();
249	        self.show_regs_short();
250	    }
251	
252	    fn cmd_next(&mut self) {
253	        if self.emu.is_halted() {
254	            println!("CPU is halted.");
255	            return;
256	        }
257	        self.emu.step_over();
258	        self.print_new_uart();
259	        self.show_location();
260	        self.show_regs_short();
261	    }
262	
263	    fn cmd_continue(&mut self) {
264	        if self.emu.is_halted() {
265	            println!("CPU is halted.");
266	            return;
267	        }
268	
269	        self.emu.resume();
270	        let result = self.emu.run_batch(100_000_000);
271	        self.print_new_uart();
272	
273	        match result.reason {
274	            StopReason::Breakpoint(addr) => println!("Breakpoint at 0x{:06X}", addr),
275	            StopReason::Halted => {
276	                println!("\nHalted after {} instructions", result.instructions_run)
277	            }
278	            _ => {}
279	        }
280	
281	        self.show_location();
282	    }
283	
284	    fn cmd_break(&mut self, arg: &str) {
285	        if arg.is_empty() {
286	            println!("Usage: break <address>");
287	            return;
288	        }
289	        if let Some(addr) = parse_addr(arg) {
290	            self.emu.add_breakpoint(addr);
291	            println!(
292	                "Breakpoint {} at 0x{:06X}",
293	                self.emu.breakpoints().len(),
294	                addr
295	            );
296	        } else {
297	            println!("Bad address: {}", arg);
298	        }
299	    }
300	
301	    fn cmd_delete(&mut self, arg: &str) {
302	        if arg.is_empty() || arg == "all" {
303	            self.emu.clear_breakpoints();
304	            println!("All breakpoints deleted.");
305	        } else if let Ok(n) = arg.parse::<usize>() {
306	            if n >= 1 {
307	                if let Some(addr) = self.emu.remove_breakpoint_by_index(n - 1) {
308	                    println!("Deleted breakpoint {} at 0x{:06X}", n, addr);
309	                } else {
310	                    println!("No breakpoint #{}", n);
311	                }
312	            }
313	        } else {
314	            println!("Usage: delete <N> or delete all");
315	        }
316	    }
317	
318	    fn cmd_info(&self, arg: &str) {
319	        match arg {
320	            "r" | "reg" | "registers" => self.show_regs(),
321	            "t" | "trace" => self.cmd_trace("20"),
322	            "b" | "break" | "breakpoints" => {
323	                let bps = self.emu.breakpoints();
324	                if bps.is_empty() {
325	                    println!("No breakpoints.");
326	                } else {
327	                    for (i, &addr) in bps.iter().enumerate() {
328	                        println!("  #{}: 0x{:06X}", i + 1, addr);
329	                    }
330	                }
331	            }
332	            "" => self.show_regs(),
333	            _ => println!("info: r(egisters), t(race), b(reakpoints)"),
334	        }
335	    }
336	
337	    fn cmd_examine(&self, arg: &str) {
338	        let (count, addr_str) = if let Some(rest) = arg.strip_prefix('/') {
339	            if let Some(space) = rest.find(' ') {
340	                let n: usize = rest[..space].parse().unwrap_or(16);
341	                (n, rest[space..].trim())
342	            } else {
343	                (16, rest)
344	            }
345	        } else {
346	            (16, arg)
347	        };
348	
349	        if addr_str.is_empty() {
350	            println!("Usage: x [/N] <address>");
351	            return;
352	        }
353	
354	        let addr = match parse_addr(addr_str) {
355	            Some(a) => a,
356	            None => {
357	                println!("Bad address: {}", addr_str);
358	                return;
359	            }
360	        };
361	
362	        let bytes = self.emu.read_memory(addr, count as u32);
363	        let mut offset = 0;
364	        while offset < bytes.len() {
365	            let row_len = std::cmp::min(16, bytes.len() - offset);
366	            print!("0x{:06X}:", addr + offset as u32);
367	            for i in 0..row_len {
368	                print!(" {:02X}", bytes[offset + i]);
369	            }
370	            print!("  |");
371	            for i in 0..row_len {
372	                let b = bytes[offset + i];
373	                if (0x20..0x7F).contains(&b) {
374	                    print!("{}", b as char);
375	                } else {
376	                    print!(".");
377	                }
378	            }
379	            println!("|");
380	            offset += row_len;
381	        }
382	    }
383	
384	    fn cmd_print(&self, arg: &str) {
385	        match arg.to_lowercase().as_str() {
386	            "r0" => println!(
387	                "r0 = 0x{:06X} ({})",
388	                self.emu.get_reg(0),
389	                self.emu.get_reg(0) as i32
390	            ),
391	            "r1" => println!(
392	                "r1 = 0x{:06X} ({})",
393	                self.emu.get_reg(1),
394	                self.emu.get_reg(1) as i32
395	            ),
396	            "r2" => println!(
397	                "r2 = 0x{:06X} ({})",
398	                self.emu.get_reg(2),
399	                self.emu.get_reg(2) as i32
400	            ),
401	            "fp" | "r3" => println!("fp = 0x{:06X}", self.emu.get_reg(3)),
402	            "sp" | "r4" => println!("sp = 0x{:06X}", self.emu.get_reg(4)),
403	            "pc" => println!("pc = 0x{:06X}", self.emu.pc()),
404	            "c" => println!("c = {}", self.emu.condition_flag()),
405	            "led" | "leds" => println!(
406	                "LED = 0x{:02X} (bit0={})",
407	                self.emu.get_led(),
408	                self.emu.get_led() & 1
409	            ),
410	            _ => {
411	                if let Some(addr) = parse_addr(arg) {
412	                    println!("[0x{:06X}] = 0x{:02X}", addr, self.emu.read_byte(addr));
413	                } else {
414	                    println!("Usage: print <register|address>");
415	                }
416	            }
417	        }
418	    }
419	
420	    fn cmd_disas(&self, arg: &str) {
421	        let parts: Vec<&str> = arg.split_whitespace().collect();
422	        let addr = if parts.is_empty() {
423	            self.emu.pc()
424	        } else {
425	            parse_addr(parts[0]).unwrap_or(self.emu.pc())
426	        };
427	        let count: usize = if parts.len() > 1 {
428	            parts[1].parse().unwrap_or(10)
429	        } else {
430	            10
431	        };
432	
433	        for (pc, text, size) in self.emu.disassemble(addr, count) {
434	            let marker = if pc == self.emu.pc() { "=> " } else { "   " };
435	            let bp = if self.emu.has_breakpoint(pc) {
436	                "*"
437	            } else {
438	                " "
439	            };
440	            let mut bytes_str = String::new();
441	            for i in 0..size {
442	                bytes_str.push_str(&format!("{:02X} ", self.emu.read_byte(pc + i)));
443	            }
444	            println!("{}{}{:06X}: {:12} {}", bp, marker, pc, bytes_str, text);
445	        }
446	    }
447	
448	    fn cmd_trace(&self, arg: &str) {
449	        let n: usize = if arg.is_empty() {
450	            20
451	        } else {
452	            arg.parse().unwrap_or(20)
453	        };
454	        let trace = self.emu.trace();
455	        let entries = trace.last_n(n);
456	        if entries.is_empty() {
457	            println!("No trace entries.");
458	        } else {
459	            for entry in &entries {
460	                println!("{}", entry);
461	            }
462	            println!("({} of {} entries shown)", entries.len(), trace.len());
463	        }
464	    }
465	
466	    fn cmd_uart(&mut self, arg: &str) {
467	        if let Some(rest) = arg
468	            .strip_prefix("send ")
469	            .or_else(|| arg.strip_prefix("tx "))
470	        {
471	            let rest = rest.trim();
472	            // Support: single char, decimal, 0x hex, or quoted string
473	            if rest.starts_with('"') && rest.ends_with('"') && rest.len() >= 2 {
474	                let s = &rest[1..rest.len() - 1];
475	                for b in s.bytes() {
476	                    self.emu.send_uart_byte(b);
477	                }
478	                println!("Sent {} byte(s) to UART RX", s.len());
479	            } else if let Some(byte) = parse_byte_value(rest) {
480	                self.emu.send_uart_byte(byte);
481	                println!("Sent 0x{:02X} ({}) to UART RX", byte, byte);
482	            } else {
483	                println!("Usage: uart send <byte|0xHH|\"string\">");
484	            }
485	        } else {
486	            let output = self.emu.get_uart_output();
487	            println!("UART output buffer ({} chars):", output.len());
488	            println!("{}", output);
489	        }
490	    }
491	
492	    fn cmd_led(&self) {
493	        let led = self.emu.get_led() & 1;
494	        let pressed = self.emu.get_button();
495	        println!(
496	            "LED D2: {} (bit0 = {})",
497	            if led != 0 { "ON" } else { "OFF" },
498	            led
499	        );
500	        println!(
501	            "Button S2: {} (bit0 = {})",
502	            if pressed { "LOW (pressed)" } else { "HIGH" },
503	            if pressed { 0 } else { 1 }
504	        );
505	    }
506	
507	    fn cmd_button(&mut self, arg: &str) {
508	        match arg {
509	            "press" | "down" | "1" => {
510	                self.emu.set_button_pressed(true);
511	                println!("Button S2: pressed (LOW)");
512	            }
513	            "release" | "up" | "0" => {
514	                self.emu.set_button_pressed(false);
515	                println!("Button S2: released (HIGH)");
516	            }
517	            "toggle" | "t" => {
518	                let currently = self.emu.get_button();
519	                self.emu.set_button_pressed(!currently);
520	                if !currently {
521	                    println!("Button S2: pressed (LOW)");
522	                } else {
523	                    println!("Button S2: released (HIGH)");
524	                }
525	            }
526	            "" => {
527	                let pressed = self.emu.get_button();
528	                println!(
529	                    "Button S2: {}",
530	                    if pressed {
531	                        "pressed (LOW)"
532	                    } else {
533	                        "released (HIGH)"
534	                    }
535	                );
536	            }
537	            _ => println!("Usage: button [press|release|toggle]"),
538	        }
539	    }
540	
541	    fn cmd_help(&self) {
542	        println!("Commands:");
543	        println!("  r, run [N]          Run N instructions (default 100M)");
544	        println!("  s, step [N]         Single step (N instructions)");
545	        println!("  n, next             Step over (skip jal calls)");
546	        println!("  c, continue         Continue from breakpoint");
547	        println!("  b, break <addr>     Set breakpoint");
548	        println!("  d, delete <N|all>   Delete breakpoint(s)");
549	        println!("  i, info [r|b]       Show registers or breakpoints");
550	        println!("  x [/N] <addr>       Examine N bytes at address");
551	        println!("  p, print <reg|addr> Print register or memory");
552	        println!("  t, trace [N]        Show last N traced instructions (default 20)");
553	        println!("  disas [addr] [N]    Disassemble N instructions");
554	        println!("  load <file.lgo>     Load LGO file");
555	        println!("  uart                Show UART output buffer");
556	        println!("  uart send <val>     Send byte to UART RX (decimal, 0xHH, or \"string\")");
557	        println!("  led                 Show LED/button state");
558	        println!("  button [press|release|toggle]  Control button S2");
559	        println!("  reset               Reset CPU");
560	        println!("  q, quit             Exit");
561	        println!();
562	        println!("Addresses: decimal, 0x-hex, or 0b-binary");
563	        println!("Empty line repeats last command.");
564	    }
565	
566	    fn show_location(&self) {
567	        let (text, _) = self.emu.disassemble_at(self.emu.pc());
568	        println!("0x{:06X}: {}", self.emu.pc(), text);
569	    }
570	
571	    fn show_regs(&self) {
572	        let s = self.emu.snapshot();
573	        println!(
574	            "  r0 = 0x{:06X}  r1 = 0x{:06X}  r2 = 0x{:06X}",
575	            s.regs[0], s.regs[1], s.regs[2]
576	        );
577	        println!(
578	            "  fp = 0x{:06X}  sp = 0x{:06X}  z  = 0x{:06X}",
579	            s.regs[3], s.regs[4], s.regs[5]
580	        );
581	        println!("  iv = 0x{:06X}  ir = 0x{:06X}", s.regs[6], s.regs[7]);
582	        println!("  pc = 0x{:06X}  c  = {}", s.pc, s.c as u8);
583	        println!("  LED = 0x{:02X}  cycles = {}", s.led, s.cycles);
584	    }
585	
586	    fn show_regs_short(&self) {
587	        let s = self.emu.snapshot();
588	        println!(
589	            "  r0={:06X} r1={:06X} r2={:06X} fp={:06X} sp={:06X} c={}",
590	            s.regs[0], s.regs[1], s.regs[2], s.regs[3], s.regs[4], s.c as u8
591	        );
592	    }
593	}
594	
595	fn parse_byte_value(s: &str) -> Option<u8> {
596	    let s = s.trim();
597	    if s.len() == 1 {
598	        return Some(s.as_bytes()[0]);
599	    }
600	    if let Some(hex) = s.strip_prefix("0x").or_else(|| s.strip_prefix("0X")) {
601	        u8::from_str_radix(hex, 16).ok()
602	    } else {
603	        s.parse::<u8>().ok()
604	    }
605	}
606	
607	fn parse_addr(s: &str) -> Option<u32> {
608	    let s = s.trim();
609	    if let Some(hex) = s.strip_prefix("0x").or_else(|| s.strip_prefix("0X")) {
610	        u32::from_str_radix(hex, 16).ok()
611	    } else if let Some(bin) = s.strip_prefix("0b") {
612	        u32::from_str_radix(bin, 2).ok()
613	    } else {
614	        s.parse().ok()
615	    }
616	}
