1	//! cor24-emu: COR24 assembler and emulator CLI
2	//!
3	//! Usage:
4	//!   cor24-emu --demo                              Run built-in LED demo
5	//!   cor24-emu --demo --speed 50000 --time 10      Run at 50k IPS for 10 seconds
6	//!   cor24-emu --run <file.s>                      Assemble and run
7	//!   cor24-emu --assemble <in.s> <out.bin> <out.lst>  Assemble to binary + listing
8	
9	use cor24_emulator::assembler::{Assembler, AssemblyResult};
10	use cor24_emulator::emulator::EmulatorCore;
11	use std::collections::VecDeque;
12	use std::env;
13	use std::fs;
14	use std::io::Write;
15	use std::thread;
16	use std::time::{Duration, Instant};
17	
18	/// Default emulation speed (instructions per second)
19	const DEFAULT_SPEED: u64 = 100_000;
20	
21	/// Default time limit in seconds
22	const DEFAULT_TIME_LIMIT: f64 = 10.0;
23	
24	const COPYRIGHT: &str = "Copyright (c) 2026 Michael A Wright";
25	const LICENSE: &str = "MIT";
26	const REPOSITORY: &str = "https://github.com/sw-embed/sw-cor24-emulator";
27	
28	fn print_version() {
29	    println!(
30	        "cor24-emu {}\n{}\nLicense: {}\nRepository: {}\n\nBuild Information:\n  Host: {}\n  Commit: {}\n  Timestamp: {}",
31	        env!("CARGO_PKG_VERSION"),
32	        COPYRIGHT,
33	        LICENSE,
34	        REPOSITORY,
35	        env!("VERGEN_BUILD_HOST"),
36	        env!("VERGEN_GIT_SHA_SHORT"),
37	        env!("VERGEN_BUILD_TIMESTAMP"),
38	    );
39	}
40	
41	fn print_short_help() {
42	    println!("cor24-emu: COR24 assembler and emulator\n");
43	    println!("Usage:");
44	    println!("  cor24-emu --demo [options]        Run built-in LED demo");
45	    println!("  cor24-emu --run <file.s> [opts]   Assemble and run");
46	    println!("  cor24-emu --load-binary <f>@<a> --entry <a>  Run pre-assembled binaries");
47	    println!("  cor24-emu --assemble <in.s> <out.bin> <out.lst>");
48	    println!();
49	    println!("Options:");
50	    println!("  -h                     Short help (this message)");
51	    println!("  --help                 Extended help with AI agent guidance");
52	    println!("  -V, --version          Version, copyright, license, build info");
53	    println!(
54	        "  --speed, -s <ips>      Instructions per second (default: {})",
55	        DEFAULT_SPEED
56	    );
57	    println!(
58	        "  --time, -t <secs>      Time limit in seconds (default: {})",
59	        DEFAULT_TIME_LIMIT
60	    );
61	    println!("  --max-instructions, -n <count>  Stop after N instructions (-1 = no limit)");
62	    println!("  --uart-input, -u <str> Send characters to UART RX (supports \\n, \\x21)");
63	    println!("  --entry, -e <label|addr> Set entry point (label name or numeric address)");
64	    println!("  --dump                 Dump CPU state, I/O, and non-zero memory after halt");
65	    println!("  --dump-uart            Show UART transaction log (chronological IN/OUT)");
66	    println!("  --trace <N>            Dump last N instructions on halt/timeout (default: 50)");
67	    println!("  --step                 Print each instruction as it executes");
68	    println!("  --terminal             Bridge stdin/stdout to UART (interactive mode)");
69	    println!("  --echo                 Local echo in terminal mode (for programs that don't echo)");
70	    println!("  --load-binary <file>@<addr>  Load raw bytes into memory at address");
71	    println!("  --patch <addr>=<value> Write 24-bit value to memory (repeatable)");
72	    println!("  --base-addr <addr>     Base address for assembly (default: 0)");
73	    println!("  --stack-kilobytes <3|8>  EBR stack size (default: 3, max: 8)");
74	    println!("  --switch <on|off>      Set button S2 state (default: off/released)");
75	    println!("  --uart-never-ready     UART TX stays busy forever (test polling)");
