                        '.'
                    }
                );
                uart_pos += 1;
            }
        }

        let result = emu.step();

        let trace = emu.trace();
        if let Some(entry) = trace.last_n(1).first() {
            println!("{}", entry);
        }

        let output = emu.get_uart_output();
        if output.len() > prev_uart_len {
            let new = &output[prev_uart_len..];
            for ch in new.chars() {
                if ch == '\n' {
                    println!("  >>> UART TX: '\\n'");
                } else {
                    println!("  >>> UART TX: '{}'  (0x{:02X})", ch, ch as u8);
                }
