            println!("\n--- Halted after {} instructions ---", n);
            break;
        }
    }

    let uart = emu.get_uart_output();
    if !uart.is_empty() {
        println!("\nUART output: {}", uart);
    }
    println!("\nExecuted {} instructions", emu.instructions_count());
    if emu.is_halted() {
        println!("CPU halted (self-branch detected)");
    }
